population.algorithm:
A modified greedy insertion with capacity-aware regret scoring and adaptive fallback using multiple seed candidates.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candInfo struct {
		assignIdx int
		deltaCost float64
		isValid   bool
	}
	for shipIDOffset := 0; shipIDOffset < len(oris); shipIDOffset++ {
		orderID := total_ship + shipIDOffset
		var feasibleCands []candInfo
		bestIdx := -1
		minDelta := 1e18
		secondMinDelta := 1e18
		for assignIdx := 0; assignIdx <= dispatch.AssignsLen; assignIdx++ {
			originalCost := dispatch.Assigns[assignIdx].Cost
			inserted := dispatch.Assigns[assignIdx].AddShip(orderID, oris[shipIDOffset], dess[shipIDOffset])
			if inserted {
				dispatch.Assigns[assignIdx].GenRoute()
				if dispatch.Assigns[assignIdx].Cost >= 0 {
					delta := dispatch.Assigns[assignIdx].Cost - originalCost
					if delta < 0 {
						delta = 0
					}
					feasibleCands = append(feasibleCands, candInfo{assignIdx: assignIdx, deltaCost: delta, isValid: true})
					if delta < minDelta {
						secondMinDelta = minDelta
						minDelta = delta
						bestIdx = assignIdx
					} else if delta < secondMinDelta {
						secondMinDelta = delta
					}
				}
				dispatch.Assigns[assignIdx].RemoveShip(orderID)
				dispatch.Assigns[assignIdx].GenRoute()
			}
		}
		if len(feasibleCands) > 0 {
			chosenIdx := bestIdx
			regretScore := secondMinDelta - minDelta
			if regretScore < 1e-9 && len(feasibleCands) > 1 {
				for _, c := range feasibleCands {
					if c.assignIdx != chosenIdx && c.deltaCost-minDelta < 1e-9 {
						chosenIdx = c.assignIdx
						break
					}
				}
			}
			dispatch.Assigns[chosenIdx].AddShip(orderID, oris[shipIDOffset], dess[shipIDOffset])
			dispatch.Assigns[chosenIdx].GenRoute()
			if chosenIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			fallbackList := []int{}
			if dispatch.AssignsLen < MAXASSIGNS {
				fallbackList = append(fallbackList, dispatch.AssignsLen)
			}
			if dispatch.AssignsLen > 0 {
				fallbackList = append(fallbackList, 0)
			}
			insertSuccess := false
			for _, fbIdx := range fallbackList {
				addOk := dispatch.Assigns[fbIdx].AddShip(orderID, oris[shipIDOffset], dess[shipIDOffset])
				if addOk {
					dispatch.Assigns[fbIdx].GenRoute()
					if dispatch.Assigns[fbIdx].Cost >= 0 {
						if fbIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen++
						}
						insertSuccess = true
						break
					} else {
						dispatch.Assigns[fbIdx].RemoveShip(orderID)
						dispatch.Assigns[fbIdx].GenRoute()
					}
				}
			}
			if !insertSuccess {
				for fbIdx := 0; fbIdx < dispatch.AssignsLen && fbIdx < MAXASSIGNS; fbIdx++ {
					addOk := dispatch.Assigns[fbIdx].AddShip(orderID, oris[shipIDOffset], dess[shipIDOffset])
					if addOk {
						dispatch.Assigns[fbIdx].GenRoute()
						if dispatch.Assigns[fbIdx].Cost >= 0 {
							insertSuccess = true
							break
						} else {
							dispatch.Assigns[fbIdx].RemoveShip(orderID)
							dispatch.Assigns[fbIdx].GenRoute()
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

