Greedy insertion with best-fit selection using marginal cost increase per assign while preserving all existing routes.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		bestIdx := -1
		bestCostIncrease := math.MaxFloat64
		origCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			origCosts[i] = dispatch.Assigns[i].Cost
		}
		// Try inserting into each existing non-empty assign first
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[ii].GenRoute()
				costInc := dispatch.Assigns[ii].Cost - origCosts[ii]
				if costInc >= 0 && costInc < bestCostIncrease {
					bestCostIncrease = costInc
					bestIdx = ii
				}
			}
			// Rollback
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
		}
		// If no existing assign accepted, try empty assigns (including beyond current length up to MAXASSIGNS)
		if bestIdx == -1 {
			for ii := 0; ii < MAXASSIGNS; ii++ {
				if ii >= dispatch.AssignsLen || dispatch.Assigns[ii].StationsLen == 0 {
					ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
					if ok {
						dispatch.Assigns[ii].GenRoute()
						if dispatch.Assigns[ii].Cost >= 0 {
							bestIdx = ii
							break
						} else {
							dispatch.Assigns[ii].RemoveShip(total_ship + jj)
							dispatch.Assigns[ii].GenRoute()
						}
					}
				}
			}
		}
		// Commit the best insertion found
		if bestIdx != -1 {
			ok := dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[bestIdx].GenRoute()
				if bestIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = bestIdx + 1
				}
			}
		} else {
			// Fallback: force insert into a new empty slot even if route generation fails? Actually safe fallback is to create a new dedicated assign.
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				dispatch.Assigns[fallbackIdx].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

