Modified greedy insertion with weighted composite scoring combining normalized distance increase, route compactness benefit, and temporal feasibility slack, using dynamic candidate filtering and probabilistic fallback exploration.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const alphaDist = 1.0
	const betaCompact = 0.3
	const gammaTime = 0.5
	const eps = 1e-9
	const exploreProb = 0.2

	type candInfo struct {
		assignIdx     int
		score         float64
		oriPos        int
		desPos        int
		origCost      float64
		newCost       float64
		valid         bool
		timeSlackSum  float64
		routeIncrease float64
	}

	nOrders := len(oris)
	for offset := 0; offset < nOrders; offset++ {
		orderID := total_ship + offset
		oriSt := oris[offset]
		desSt := dess[offset]

		var candidates []candInfo
		bestCandIdx := -1

		for aIdx := 0; aIdx <= dispatch.AssignsLen; aIdx++ {
			origCost := dispatch.Assigns[aIdx].Cost
			ok := dispatch.Assigns[aIdx].AddShip(orderID, oriSt, desSt)
			if ok {
				dispatch.Assigns[aIdx].GenRoute()
				newCost := dispatch.Assigns[aIdx].Cost
				if newCost >= 0 {
					incr := newCost - origCost
					if incr < 0 {
						incr = 0
					}

					compactBenefit := 0.0
					if aIdx < dispatch.AssignsLen && dispatch.Assigns[aIdx].StationCurrent.X != 0 || dispatch.Assigns[aIdx].StationCurrent.Y != 0 {
						distToOri := cal_dis(dispatch.Assigns[aIdx].StationCurrent, oriSt)
						compactBenefit = 1.0 / (1.0 + distToOri)
					}

					timeSlack := 0.0
					if oriSt.TimeStart >= 0 && desSt.TimeEnd >= 0 {
						windowWidth := float64(desSt.TimeEnd - oriSt.TimeStart)
						if windowWidth > 0 {
							timeSlack = 1.0 / (1.0 + windowWidth)
						}
					}

					compositeScore := alphaDist*incr - betaCompact*compactBenefit - gammaTime*timeSlack

					candidates = append(candidates, candInfo{
						assignIdx:     aIdx,
						score:         compositeScore,
						origCost:      origCost,
						newCost:       newCost,
						valid:         true,
						timeSlackSum:  timeSlack,
						routeIncrease: incr,
					})
					if bestCandIdx == -1 || compositeScore < candidates[bestCandIdx].score {
						bestCandIdx = len(candidates) - 1
					}
				}
				dispatch.Assigns[aIdx].RemoveShip(orderID)
				dispatch.Assigns[aIdx].GenRoute()
			}
		}

