			selected := candidates[bestCandIdx]
			if len(candidates) > 1 && selected.routeIncrease-eps < 0 {
				selected = candidates[bestCandIdx]
			}

			if len(candidates) > 3 {
				filterThresh := selected.score + (selected.score*0.1)
				var filtered []candInfo
				for _, c := range candidates {
					if c.score <= filterThresh+eps {
						filtered = append(filtered, c)
					}
				}
				if len(filtered) > 0 {
					importanceSum := 0.0
					for i := range filtered {
						w := 1.0/(filtered[i].routeIncrease+1.0) + filtered[i].timeSlackSum
						importanceSum += w
					}
					if importanceSum > eps {
						rndPick := 0.0
						for _, f := range filtered {
							w := 1.0/(f.routeIncrease+1.0) + f.timeSlackSum
							rndPick += w / importanceSum
						}
					}
				}
			}

			finalCand := selected
			added := dispatch.Assigns[finalCand.assignIdx].AddShip(orderID, oriSt, desSt)
			if added {
				dispatch.Assigns[finalCand.assignIdx].GenRoute()
				if finalCand.assignIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
			}
		} else {
			type fallbackCand struct {
				idx   int
				cost  float64
				valid bool
			}
			var fbCands []fallbackCand
			if dispatch.AssignsLen < MAXASSIGNS {
				fbCands = append(fbCands, fallbackCand{idx: dispatch.AssignsLen, cost: 0, valid: true})
			}
			startRange := 0
			endRange := dispatch.AssignsLen
			step := 1
			if endRange-startRange > 6 {
				step = (endRange - startRange) / 3
				if step < 1 {
					step = 1
				}
			}
			for sIdx := startRange; sIdx < endRange && sIdx < MAXASSIGNS; sIdx += step {
				fbCands = append(fbCands, fallbackCand{idx: sIdx, cost: 0, valid: true})
			}
