						break
					} else {
						dispatch.Assigns[fc.idx].RemoveShip(orderID)
						dispatch.Assigns[fc.idx].GenRoute()
					}
				}
			}
			if !inserted {
				for sIdx := 0; sIdx < dispatch.AssignsLen && sIdx < MAXASSIGNS; sIdx++ {
					ok := dispatch.Assigns[sIdx].AddShip(orderID, oriSt, desSt)
					if ok {
						dispatch.Assigns[sIdx].GenRoute()
						if dispatch.Assigns[sIdx].Cost >= 0 {
