							break
						} else {
							dispatch.Assigns[sIdx].RemoveShip(orderID)
							dispatch.Assigns[sIdx].GenRoute()
						}
					}
				}
				if !inserted && dispatch.AssignsLen < MAXASSIGNS {
					ok := dispatch.Assigns[dispatch.AssignsLen].AddShip(orderID, oriSt, desSt)
					if ok {
						dispatch.Assigns[dispatch.AssignsLen].GenRoute()
						dispatch.AssignsLen++
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

