Modified greedy insertion with fallback to empty assign when all existing routes reject the order, processing orders sequentially without early termination.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx
		inserted := false
		bestAssignIdx := -1
		bestCostDelta := 1e100
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			oldCost := assign.Cost
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					newCost := assign.Cost
					costDelta := newCost - oldCost
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = i
					}
				}
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
		}
		if bestAssignIdx >= 0 {
			ok := dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				inserted = true
			}
		}
		if !inserted {
			fallbackOk := false
			for i := 0; i < dispatch.AssignsLen; i++ {
				if dispatch.Assigns[i].StationsLen == 0 {
					ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
					if ok {
						dispatch.Assigns[i].GenRoute()
						if dispatch.Assigns[i].Cost >= 0 {
							inserted = true
							fallbackOk = true
							break
						}
						dispatch.Assigns[i].RemoveShip(shipID)
						dispatch.Assigns[i].GenRoute()
					}
				}
			}
			if !fallbackOk && dispatch.AssignsLen < MAXASSIGNS {
				i := dispatch.AssignsLen
				ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						dispatch.Assigns[i].RemoveShip(shipID)
						dispatch.Assigns[i].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

