const (
	alpha       = 0.7
	beta        = 0.25
	gamma       = 100.0
	delta       = 0.15
	zeta        = 0.02
	regretFactor = 0.2
	minRegretThreshold = 0.01
)
orderCount := len(oris)
if orderCount == 0 || orderCount != len(dess) {
	dispatch.RenewnTotalCost()
	return dispatch
}
type cand struct {
	idx       int
	score     float64
	marginal  float64
	feasible  bool
	newAssign bool
}
baseOrderIndices := make([]int, orderCount)
for i := 0; i < orderCount; i++ {
	baseOrderIndices[i] = total_ship + i
}
sortedOrders := make([]int, orderCount)
for i := range sortedOrders {
	sortedOrders[i] = i
}
for i := 0; i < orderCount; i++ {
	for j := i + 1; j < orderCount; j++ {
		wi := cal_dis(oris[sortedOrders[i]], dess[sortedOrders[i]]) * float64(oris[sortedOrders[i]].Load+dess[sortedOrders[i]].Load)
		wj := cal_dis(oris[sortedOrders[j]], dess[sortedOrders[j]]) * float64(oris[sortedOrders[j]].Load+dess[sortedOrders[j]].Load)
		if wj > wi {
			sortedOrders[i], sortedOrders[j] = sortedOrders[j], sortedOrders[i]
		}
	}
}
for _, shipPos := range sortedOrders {
	ori := oris[shipPos]
	des := dess[shipPos]
	shipID := baseOrderIndices[shipPos]
	bestCands := make([]cand, 0, dispatch.AssignsLen+2)
	for i := 0; i < dispatch.AssignsLen; i++ {
		oldCost := dispatch.Assigns[i].Cost
		ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
		if !ok {
			continue
		}
		dispatch.Assigns[i].GenRoute()
		if dispatch.Assigns[i].Cost < 0 {
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].GenRoute()
			continue
		}
		marginal := dispatch.Assigns[i].Cost - oldCost
		var stationCount int
		if assignFields, ok := interface{}(&dispatch.Assigns[i]).(interface{ GetStations() []Station }); ok {
			stationCount = len(assignFields.GetStations())
		} else {
			stationCount = 0
		}
		loadBalancePenalty := float64(stationCount) * zeta
		timeWindowPenalty := 0.0
		if ori.TimeStart > 0 || des.TimeStart > 0 {
			timeSlack := float64(ori.TimeEnd-ori.TimeStart+des.TimeEnd-des.TimeStart) / 60.0
			if timeSlack < 30.0 {
				timeWindowPenalty = delta * (30.0 - timeSlack)
			}
		}
		directDist := cal_dis(ori, des)
		score := alpha*marginal + beta*(directDist/gamma) + loadBalancePenalty + timeWindowPenalty
		bestCands = append(bestCands, cand{idx: i, score: score, marginal: marginal, feasible: true, newAssign: false})
		dispatch.Assigns[i].RemoveShip(shipID)
		dispatch.Assigns[i].GenRoute()
	}
