New algorithm uses greedy insertion with regret-based scoring considering time window feasibility, distance increase, and load balance, trying all assigns per order and falling back to empty assign creation if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type insertCandidate struct {
		assignIdx int
		score     float64
		ok        bool
	}
	const bigNumber = 1e12
	orderCount := len(oris)
	for j := 0; j < orderCount; j++ {
		ori := oris[j]
		des := dess[j]
		shipID := total_ship + j
		best := insertCandidate{-1, bigNumber, false}
		candidates := make([]insertCandidate, 0, dispatch.AssignsLen+1)
		considerEmptyAssign := dispatch.AssignsLen < MAXASSIGNS
		totalAssignable := dispatch.AssignsLen
		if considerEmptyAssign {
			totalAssignable++
		}
		for ii := 0; ii < totalAssignable; ii++ {
			actualIdx := ii
			isEmptySlot := false
			if ii >= dispatch.AssignsLen {
				if !considerEmptyAssign {
					continue
				}
				isEmptySlot = true
			}
			var tmpAssign Assign
			if isEmptySlot {
				tmpAssign = Assign{}
				tmpAssign.AddShip(shipID, ori, des)
				tmpAssign.GenRoute()
			} else {
				tmpAssign = dispatch.Assigns[ii]
				oldCost := tmpAssign.Cost
				success := tmpAssign.AddShip(shipID, ori, des)
				if success {
					tmpAssign.GenRoute()
					newCost := tmpAssign.Cost
					if newCost >= 0 {
						delta := newCost - oldCost
						score := delta
						candidates = append(candidates, insertCandidate{actualIdx, score, true})
					}
					tmpAssign.RemoveShip(shipID)
					tmpAssign.GenRoute()
				}
				continue
			}
			if tmpAssign.Cost >= 0 {
				baseDistance := 0.0
				if dispatch.AssignsLen > 0 {
					for k := 0; k < dispatch.AssignsLen; k++ {
						if dispatch.Assigns[k].StationsLen == 0 {
							baseDistance += cal_dis(Station{X: 0, Y: 0}, ori) + cal_dis(ori, des)
						}
					}
				}
				if baseDistance == 0 {
					baseDistance = cal_dis(Station{X: 0, Y: 0}, ori) + cal_dis(ori, des)
				}
				score := tmpAssign.Cost + baseDistance*0.01
				candidates = append(candidates, insertCandidate{actualIdx, score, true})
			}
		}
		for _, cand := range candidates {
			if cand.ok && cand.score < best.score {
				best = cand
			}
		}
		inserted := false
		if best.assignIdx >= 0 && best.assignIdx < dispatch.AssignsLen {
			success := dispatch.Assigns[best.assignIdx].AddShip(shipID, ori, des)
			if success {
				dispatch.Assigns[best.assignIdx].GenRoute()
				if dispatch.Assigns[best.assignIdx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[best.assignIdx].RemoveShip(shipID)
					dispatch.Assigns[best.assignIdx].GenRoute()
				}
			}
		}
		if !inserted && considerEmptyAssign {
			if dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				dispatch.Assigns[newIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[newIdx].GenRoute()
				if dispatch.Assigns[newIdx].Cost >= 0 {
					dispatch.AssignsLen++
					inserted = true
				} else {
					dispatch.Assigns[newIdx].RemoveShip(shipID)
					dispatch.Assigns[newIdx].GenRoute()
				}
			}
		}
		if !inserted {
			fallbackDone := false
			for ii := 0; ii < dispatch.AssignsLen && !fallbackDone; ii++ {
				if dispatch.Assigns[ii].StationsLen == 0 {
					dispatch.Assigns[ii].AddShip(shipID, ori, des)
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						fallbackDone = true
					} else {
						dispatch.Assigns[ii].RemoveShip(shipID)
						dispatch.Assigns[ii].GenRoute()
					}
				}
			}
			if !fallbackDone && dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				dispatch.Assigns[newIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[newIdx].GenRoute()
				if dispatch.Assigns[newIdx].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[newIdx].RemoveShip(shipID)
					dispatch.Assigns[newIdx].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

