Greedy insertion with regret-based look-ahead, penalizing marginal distance increase and time-window violations while preferring less loaded assigns.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const (
		alpha  = 0.6
		beta   = 0.3
		gamma  = 120.0
		regretK = 2
	)
	orderCount := len(oris)
	if orderCount == 0 || orderCount != len(dess) {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	type cand struct {
		idx       int
		score     float64
		marginal  float64
		feasible  bool
		newAssign bool
	}
	baseOrderIndices := make([]int, orderCount)
	for i := 0; i < orderCount; i++ {
		baseOrderIndices[i] = total_ship + i
	}
	sortedOrders := make([]int, orderCount)
	for i := range sortedOrders {
		sortedOrders[i] = i
	}
	for i := 0; i < orderCount; i++ {
		for j := i + 1; j < orderCount; j++ {
			di := cal_dis(oris[sortedOrders[i]], dess[sortedOrders[i]])
			dj := cal_dis(oris[sortedOrders[j]], dess[sortedOrders[j]])
			if di < dj {
				sortedOrders[i], sortedOrders[j] = sortedOrders[j], sortedOrders[i]
			}
		}
	}

	for _, shipPos := range sortedOrders {
		ori := oris[shipPos]
		des := dess[shipPos]
		shipID := baseOrderIndices[shipPos]
		bestCands := make([]cand, 0, dispatch.AssignsLen+regretK)
		for i := 0; i < dispatch.AssignsLen; i++ {
			oldCost := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if !ok {
				continue
			}
			dispatch.Assigns[i].GenRoute()
			if dispatch.Assigns[i].Cost < 0 {
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].GenRoute()
				continue
			}
			marginal := dispatch.Assigns[i].Cost - oldCost
			loadPen := 0.0
			if capEst := len(dispatch.Assigns[i].Stations); capEst > 0 {
				loadPen = float64(capEst) * 0.0005
			}
			twPenalty := 0.0
			directDist := cal_dis(ori, des)
			utilScore := alpha*marginal + beta*(directDist/gamma) + loadPen + twPenalty
			bestCands = append(bestCands, cand{idx: i, score: utilScore, marginal: marginal, feasible: true, newAssign: false})
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].GenRoute()
		}
		inserted := false
		sort.Slice(bestCands, func(a, b int) bool {
			return bestCands[a].score < bestCands[b].score
		})
		candidateLimit := len(bestCands)
		if candidateLimit > 0 {
			if candidateLimit >= 2 {
				regret := bestCands[1].score - bestCands[0].score
				if regret > 0 {
					bestCands[0].score -= regret * 0.15
				}
			}
			chosen := bestCands[0]
			if chosen.feasible {
				ok := dispatch.Assigns[chosen.idx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[chosen.idx].GenRoute()
					if dispatch.Assigns[chosen.idx].Cost >= 0 {
						inserted = true
					} else {
						dispatch.Assigns[chosen.idx].RemoveShip(shipID)
						dispatch.Assigns[chosen.idx].GenRoute()
					}
				}
			}
		}
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			targetIdx := dispatch.AssignsLen
			ok := dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[targetIdx].GenRoute()
				if dispatch.Assigns[targetIdx].Cost >= 0 {
					dispatch.AssignsLen++
					inserted = true
				} else {
					dispatch.Assigns[targetIdx].RemoveShip(shipID)
					dispatch.Assigns[targetIdx].GenRoute()
				}
			}
		}
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			startIdx := dispatch.AssignsLen
			for j := startIdx; j < MAXASSIGNS; j++ {
				ok := dispatch.Assigns[j].AddShip(shipID, ori, des)
				if !ok {
					continue
				}
				dispatch.Assigns[j].GenRoute()
				if dispatch.Assigns[j].Cost >= 0 {
					dispatch.AssignsLen = j + 1
					inserted = true
					break
				}
				dispatch.Assigns[j].RemoveShip(shipID)
				dispatch.Assigns[j].GenRoute()
			}
		}
		if !inserted && dispatch.AssignsLen == 0 && MAXASSIGNS > 0 {
			ok := dispatch.Assigns[0].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[0].GenRoute()
				if dispatch.Assigns[0].Cost >= 0 {
					dispatch.AssignsLen = 1
					inserted = true
				} else {
					dispatch.Assigns[0].RemoveShip(shipID)
					dispatch.Assigns[0].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

