	const beta = 0.3
	const gamma = 100.0
	for shipIdx := range oris {
		var bestCand cand
		bestCand.score = 1e18
		var feasCands []cand
		for i := 0; i < dispatch.AssignsLen; i++ {
			cb := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if ok {
				dispatch.Assigns[i].GenRoute()
				if dispatch.Assigns[i].Cost >= 0 {
					mc := dispatch.Assigns[i].Cost - cb
					stationsCnt := len(dispatch.Assigns[i].Stations)
