Greedily insert each ship by evaluating feasibility and marginal cost across all existing and potential new assigns, breaking ties by distance heuristic, and using fallback seed insertion with route regeneration after each permanent addition.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for j := 0; j < orderCount; j++ {
		orderID := total_ship + j
		ori := oris[j]
		des := dess[j]
		bestIdx := -1
		bestMarginalCost := 1e100
		bestDistIncrease := 1e100

		evaluateUpTo := dispatch.AssignsLen
		if evaluateUpTo < MAXASSIGNS && (evaluateUpTo == 0 || evaluateUpTo <= j) {
			evaluateUpTo++
		}

		for idx := 0; idx < evaluateUpTo; idx++ {
			assignBackup := dispatch.Assigns[idx]
			oldCost := assignBackup.Cost
			addOk := assignBackup.AddShip(orderID, ori, des)
			if !addOk {
				continue
			}
			assignBackup.GenRoute()
			newCost := assignBackup.Cost
			if newCost < 0 {
				assignBackup.RemoveShip(orderID)
				assignBackup.GenRoute()
				continue
			}
			marginalCost := newCost - oldCost
			var distInc float64 = 0
			s1 := assignBackup.StationCurrent
			if s1.X != -9999 {
				distInc += cal_dis(s1, ori)
			}
			distInc += cal_dis(ori, des)

			isBetter := false
			if marginalCost < bestMarginalCost-1e-9 {
				isBetter = true
			} else if marginalCost < bestMarginalCost+1e-9 && distInc < bestDistIncrease-1e-9 {
				isBetter = true
			}
			if isBetter {
				bestMarginalCost = marginalCost
				bestDistIncrease = distInc
				bestIdx = idx
			}
			assignBackup.RemoveShip(orderID)
			assignBackup.GenRoute()
		}

		targetIdx := bestIdx
		if targetIdx == -1 {
			targetIdx = dispatch.AssignsLen
			if targetIdx >= MAXASSIGNS {
				fallbackSeed := 0
				minLoaded := 1<<31 - 1
				for k := 0; k < dispatch.AssignsLen; k++ {
					curLoad := 0
					for _, st := range dispatch.Assigns[k].Stations {
						if st.ReqCode == orderID {
							curLoad += st.Load
						}
					}
					if curLoad < minLoaded {
						minLoaded = curLoad
						fallbackSeed = k
					}
				}
				targetIdx = fallbackSeed
			}
		}

		permanentAssign := &dispatch.Assigns[targetIdx]
		addPermanent := permanentAssign.AddShip(orderID, ori, des)
		if addPermanent {
			permanentAssign.GenRoute()
			if targetIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = targetIdx + 1
			}
		} else {
			permanentAssign.RemoveShip(orderID)
			permanentAssign.GenRoute()
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

