func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type Candidate struct {
		idx     int
		delta   float64
		empty   bool
		feasible bool
	}
	activeIdxs := make([]int, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			activeIdxs = append(activeIdxs, i)
		}
	}
	perm := make([]int, len(activeIdxs))
	for i := range perm {
		perm[i] = activeIdxs[i]
	}
	rand.Shuffle(len(perm), func(i, j int) {
		perm[i], perm[j] = perm[j], perm[i]
	})
	nextEmpty := dispatch.AssignsLen
	if nextEmpty >= MAXASSIGNS {
		nextEmpty = -1
	}
	for jj := range oris {
		bestCand := Candidate{-1, 0.0, false, false}
		orderId := total_ship + jj
		ori := oris[jj]
		des := dess[jj]
		candidates := make([]Candidate, 0, MAXASSIGNS)
