			ok := dispatch.Assigns[idx].AddShip(orderId, ori, des)
			if ok {
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost >= 0 {
					delta := dispatch.Assigns[idx].Cost - baseCosts[idx]
					candidates = append(candidates, Candidate{idx, delta, false, true})
				}
				dispatch.Assigns[idx].RemoveShip(orderId)
				dispatch.Assigns[idx].GenRoute()
			}
		}
