Iteratively insert each ship using a multi-criteria greedy evaluation that considers marginal cost increase, distance to current location, remaining capacity proxy, and time window urgency, with fallback insertion based on minimal violation score when no feasible insertion is found.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx   int
		score float64
		ok    bool
	}
	nOrders := len(oris)
	for j := 0; j < nOrders; j++ {
		ori := oris[j]
		des := dess[j]
		shipID := total_ship + j
		bestFeasible := candidate{-1, 1e18, false}
		for i := 0; i < dispatch.AssignsLen; i++ {
			a := &dispatch.Assigns[i]
			oldCost := a.Cost
			if a.AddShip(shipID, ori, des) {
				a.GenRoute()
				newCost := a.Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					timeUrgency := 0.0
					if ori.TimeStart > 0 {
						timeUrgency = 0.05 * float64(ori.TimeStart)
					}
					score := delta*1.4 + 0.25*cal_dis(a.StationCurrent, ori) + timeUrgency
					if score < bestFeasible.score {
						bestFeasible.idx = i
						bestFeasible.score = score
						bestFeasible.ok = true
					}
				}
				a.RemoveShip(shipID)
				a.GenRoute()
			}
		}
		if dispatch.AssignsLen < MAXASSIGNS {
			tmp := &dispatch.Assigns[dispatch.AssignsLen]
			if tmp.AddShip(shipID, ori, des) {
				tmp.GenRoute()
				newCost := tmp.Cost
				if newCost >= 0 {
					score := newCost*0.75 + 0.5*cal_dis(tmp.StationCurrent, ori)
					if score < bestFeasible.score {
						bestFeasible.idx = dispatch.AssignsLen
						bestFeasible.score = score
						bestFeasible.ok = true
					}
				}
				tmp.RemoveShip(shipID)
				tmp.GenRoute()
			}
		}
		inserted := false
		if bestFeasible.ok {
			targetIdx := bestFeasible.idx
			if targetIdx == dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
			dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[targetIdx].GenRoute()
			inserted = true
		}
		if !inserted {
			fallbackIdx := -1
			minViolation := 1e18
			for i := 0; i < dispatch.AssignsLen; i++ {
				a := &dispatch.Assigns[i]
				if a.AddShip(shipID, ori, des) {
					a.GenRoute()
					inserted = true
					break
				} else {
					a.RemoveShip(shipID)
					baseDist := cal_dis(a.StationCurrent, ori)
					timePenalty := 0.0
					if ori.TimeEnd > 0 && ori.TimeStart > 0 {
						windowWidth := float64(ori.TimeEnd - ori.TimeStart)
						if windowWidth > 0 {
							timePenalty = 10.0 / windowWidth
						}
					}
					loadFactor := 1.0
					if a.StationCurrent.Load > 0 {
						loadFactor = 1.0 + float64(a.StationCurrent.Load)*0.01
					}
					violScore := baseDist*loadFactor*2.2 + float64(nOrders-j)*0.65 + timePenalty
					if violScore < minViolation {
						minViolation = violScore
						fallbackIdx = i
					}
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(shipID, ori, des)
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				dispatch.AssignsLen++
				inserted = true
			} else if !inserted && fallbackIdx >= 0 {
				dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[fallbackIdx].GenRoute()
				inserted = true
			}
			if !inserted {
				if dispatch.AssignsLen < MAXASSIGNS {
					dispatch.Assigns[dispatch.AssignsLen].AddShip(shipID, ori, des)
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
					dispatch.AssignsLen++
				} else {
					minSimpleViol := 1e18
					simpleIdx := -1
					for i := 0; i < dispatch.AssignsLen; i++ {
						dist := cal_dis(dispatch.Assigns[i].StationCurrent, ori)
						if dist < minSimpleViol {
							minSimpleViol = dist
							simpleIdx = i
						}
					}
					if simpleIdx >= 0 {
						dispatch.Assigns[simpleIdx].AddShip(shipID, ori, des)
						dispatch.Assigns[simpleIdx].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

