func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    const wCost = 0.6
    const wTime = 0.25
    const wDist = 0.15
    type candidate struct {
        assignIdx int
        oldCost   float64
        newCost   float64
        feasible  bool
        timeScore float64
        distScore float64
        composite float64
    }
    orderIndices := make([]int, len(oris))
    for i := range orderIndices {
        orderIndices[i] = i
    }
    rand.Shuffle(len(orderIndices), func(i, j int) {
        orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
    })
    nextNewIdx := dispatch.AssignsLen
    for _, idx := range orderIndices {
        var cands []candidate
        for aIdx := 0; aIdx < nextNewIdx; aIdx++ {
            oldCost := dispatch.Assigns[aIdx].Cost
            ok := dispatch.Assigns[aIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
            if !ok {
                dispatch.Assigns[aIdx].RemoveShip(total_ship + idx)
                continue
            }
            dispatch.Assigns[aIdx].GenRoute()
            newCost := dispatch.Assigns[aIdx].Cost
            feasible := newCost >= 0
