            if feasible {
                delta := newCost - oldCost
                maxAllowed := 100000.0
                if delta < 0 {
                    timeScore = 1.0
                } else if delta > maxAllowed {
                    timeScore = 0.0
                } else {
                    timeScore = 1.0 - (delta / maxAllowed)
